def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    n = len(bins)
    priorities = np.zeros(n)
    for i in range(n):
        if bins[i] == 0:
            priorities[i] = float('inf')
            continue
        ratio = item / bins[i]
        score = 0
        if ratio > 2:
            score = 2000 + 20 * (ratio - 2)**3
        elif ratio > 1:
            score = 1000 + 15 * (ratio - 1)**2
        else:
            if ratio > 0.9:
                score += 80 * ratio
            elif ratio > 0.75:
                score += 60 * ratio
            elif ratio > 0.5:
                score += 30 * ratio
            else:
                score += 10 * ratio
            if bins[i] < 5:
                score += 10
            elif bins[i] < 20:
                score += 5
            elif bins[i] > 150:
                score -= 15
            elif bins[i] > 80:
                score -= 7
        if i % 3 == 0:
            score *= 1.2
        elif i % 3 == 1:
            score *= 0.85
        else:
            score *= 0.95
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if len(finite_priorities) == 0:
        return priorities
    min_priority = np.min(finite_priorities)
    max_priority = np.max(finite_priorities)
    for i in range(n):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_priority + 150
        else:
            if priorities[i] < 0.3 * max_priority:
                priorities[i] += 20
            for j in range(n):
                if j != i:
                    diff = abs(bins[i] - bins[j])
                    if diff < 10 and priorities[i] > priorities[j]:
                        priorities[i] -= diff * 0.5
                    elif diff >= 10 and priorities[i] < priorities[j]:
                        priorities[i] += diff * 0.1
    return priorities
